import React, { useState, useEffect } from "react";
import Sidebar from "../../components/Admin/Sidebar";
import TopBar from "../../components/Admin//TopBar";
import DataTable from "react-data-table-component";
import AdminCompanyTopbar from "../../components/Admin/company/AdminCompanyTopbar";
import CompanyProfileModal from "../../components/Admin/company/Companyprofilemodal";
import {
  Eye, Share2, FileText, File, Building2, Users, User,
} from "lucide-react";
import { Modal, Button } from "antd";
import { FaEllipsisV, FaBuilding, FaProjectDiagram, FaArrowLeft } from "react-icons/fa";
import { FaDownload, FaEye } from "react-icons/fa";
import axios from "axios";
import { useNavigate, Link, useParams } from "react-router-dom";
import { API_BASE_URL } from "../../config/config";


function AdminUserAllDetails() {
  const { id } = useParams();
  document.title = "Company Detail - Admin";
  const apiUrlAll = API_BASE_URL + "api/admin/adminall/";
  const [istotalDocs, settotalDocs] = useState("");
  const [totalsignatory, settotalsignatory] = useState("");
  const [userData, setuserData] = useState("");
  const [CompanyName, setCompanyName] = useState("");
  const navigate = useNavigate();
  const [totalinvestor, settotalinvestor] = useState("");
  const [total_shared_reports, settotal_shared_reports] = useState("");

  // ── Company Profile Modal state ──
  const [showProfileModal, setShowProfileModal] = useState(false);

  useEffect(() => { totalDocs(); }, []);

  const totalDocs = async () => {
    let formData = { company_id: id };
    try {
      const res = await axios.post(apiUrlAll + "totalDocs", formData, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      var respo = res.data;
      settotalDocs(respo.total_docs);
      settotalsignatory(respo.total_signatory);
      settotalinvestor(respo.total_investor);
      settotal_shared_reports(respo.total_shared_reports);
      setCompanyName(respo.company_name);
    } catch (err) {
      if (err.request) console.error("Request data:", err.request);
      else console.error("Error message:", err.message);
    }
  };

  const [records, setrecords] = useState([]);
  const [recordsPrev, setrecordsPrev] = useState([]);
  const [searchText, setSearchText] = useState("");

  function formatCurrentDate(input) {
    const date = new Date(input);
    if (isNaN(date)) return "";
    const months = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    const day = date.getDate();
    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return "th";
      switch (n % 10) { case 1: return "st"; case 2: return "nd"; case 3: return "rd"; default: return "th"; }
    };
    return `${months[date.getMonth()]} ${day}${getOrdinal(day)}, ${date.getFullYear()}`;
  }

  const [isModalVisible, setIsModalVisible] = useState(false);
  const [selectedRole, setSelectedRole] = useState("");

  const handleViewRole = (row) => {
    setSelectedRole(row.signature_role);
    setIsModalVisible(true);
  };
  const handleCloseModal = () => {
    setIsModalVisible(false);
    setSelectedRole("");
  };

  const columns = [
    { name: "First Name", selector: (row) => row.first_name, sortable: true },
    { name: "Last Name", selector: (row) => row.last_name, sortable: true },
    { name: "Email", selector: (row) => row.signatory_email, sortable: true },
    { name: "Phone", selector: (row) => row.signatory_phone, sortable: true },
    {
      name: "Role",
      selector: (row) => row.signatory_role,
      sortable: true,
      cell: (row) => (
        <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
          <span>{row.signatory_role}</span>
          <Button onClick={() => handleViewRole(row)} type="primary" icon={<FaEye />} size="small">View</Button>
        </div>
      ),
    },
    {
      name: "Joined",
      selector: (row) => row.access_status,
      sortable: true,
      cell: (row) => {
        const status = row.access_status
          ? row.access_status.charAt(0).toUpperCase() + row.access_status.slice(1) : "";
        const color = row.access_status?.toLowerCase() === "pending" ? "red"
          : row.access_status?.toLowerCase() === "active" ? "green" : "black";
        return <span style={{ color }}>{status}</span>;
      },
    },
  ];

  const filteredData = records.filter((item) => {
    const search = searchText.toLowerCase();
    return (
      (item.document_name || "").toLowerCase().includes(search) ||
      formatCurrentDate(item.created_at).toLowerCase().includes(search) ||
      (item.download || "").toLowerCase().includes(search)
    );
  });

  useEffect(() => { getcompanySignatory(); }, []);
  const getcompanySignatory = async () => {
    let formData = { company_id: id };
    try {
      const res = await axios.post(apiUrlAll + "getcompanySignatory", formData, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      setrecords(res.data.results);
    } catch (err) {
      if (err.request) console.error("Request data:", err.request);
      else console.error("Error message:", err.message);
    }
  };

  const [recordsinvestor, setrecordsinvestor] = useState([]);
  const [recordsexport, setrecordsexport] = useState([]);
  const [viewInvestorDetail, setviewInvestorDetail] = useState(false);

  const customStyles = {
    table: { style: { overflow: "visible", minWidth: "100%", boxShadow: "0 1px 3px rgba(0,0,0,.1)", borderRadius: "12px", border: "1px solid #e5e7eb" } },
    headCells: { style: { backgroundColor: "#f9fafb", fontWeight: "600", fontSize: "13px", color: "#374151", textTransform: "uppercase", letterSpacing: "0.5px", padding: "16px 12px", borderBottom: "2px solid #e5e7eb" } },
    cells: { style: { padding: "14px 12px", fontSize: "14px", color: "#1f2937", backgroundColor: "#ffffff" } },
    rows: {
      style: { fontSize: "14px", fontWeight: "500", minHeight: "56px", transition: "background-color 0.15s ease", "&:not(:last-of-type)": { borderBottom: "1px solid #f3f4f6" }, "&:hover": { backgroundColor: "#f9fafb", cursor: "pointer" } },
      stripedStyle: { backgroundColor: "#fafafa" },
    },
    pagination: { style: { backgroundColor: "#f9fafb", padding: "14px 16px", borderTop: "1px solid #e5e7eb", borderBottomLeftRadius: "12px", borderBottomRightRadius: "12px", fontSize: "14px", color: "#6b7280" } },
  };

  const [openDropdown, setOpenDropdown] = useState(null);
  const toggleDropdown = (id) => { setOpenDropdown(openDropdown === id ? null : id); };

  const [InvestorDetail, setInvestorDetail] = useState([]);
  const apiUrlCompany = API_BASE_URL + "api/admin/company/";

  const columnsinvestor = [
    { name: "First Name", selector: (row) => row.first_name, sortable: true },
    { name: "Last Name", selector: (row) => row.last_name, sortable: true },
    { name: "Email", selector: (row) => row.email, sortable: true },
    { name: "Phone", selector: (row) => row.phone, sortable: true },
    {
      name: "Register",
      selector: (row) => row.is_register,
      sortable: true,
      cell: (row) => {
        const isRegistered = row.is_register === "Yes" || row.is_register === "yes";
        return (
          <span style={{ display: "inline-flex", alignItems: "center", gap: "6px", padding: "4px 12px", borderRadius: "6px", fontSize: "13px", fontWeight: "500", backgroundColor: isRegistered ? "#dcfce7" : "#fee2e2", color: isRegistered ? "#166534" : "#991b1b", border: `1px solid ${isRegistered ? "#bbf7d0" : "#fecaca"}` }}>
            <span style={{ width: "6px", height: "6px", borderRadius: "50%", backgroundColor: isRegistered ? "#22c55e" : "#ef4444" }} />
            {row.is_register}
          </span>
        );
      },
    },
  ];

  const filteredInvestors = InvestorDetail.filter((row) => {
    const search = searchText.toLowerCase();
    return (
      (row.first_name || "").toLowerCase().includes(search) ||
      (row.last_name || "").toLowerCase().includes(search) ||
      (row.email || "").toLowerCase().includes(search) ||
      (row.phone || "").toLowerCase().includes(search) ||
      (row.is_register || "").toLowerCase().includes(search)
    );
  });

  useEffect(() => { getcompanyInvestor(); }, []);
  const getcompanyInvestor = async () => {
    let formData = { company_id: id };
    try {
      const res = await axios.post(apiUrlCompany + "getcompanyInvestor", formData, {
        headers: { Accept: "application/json", "Content-Type": "application/json" },
      });
      setInvestorDetail(res.data.results);
    } catch (err) {
      if (err.request) console.error("Request data:", err.request);
      else console.error("Error message:", err.message);
    }
  };

  return (
    <>
      <div>
        <div className="d-flex align-items-start gap-0">
          <Sidebar />
          <div className="d-flex flex-column gap-0 dashboard_padding w-100">
            <TopBar />
            <section className="dashboard_adminh">
              <div className="container-xl">
                <div className="row gy-4">
                  <div className="col-12">
                    <h2>{userData.company_name}</h2>
                  </div>

                  <div className="col-12">
                    <div className="row gy-4">
                      <AdminCompanyTopbar id={id} />

                      {/* ── Company Profile Button ── */}
                      <div className="col-12 d-flex justify-content-end align-items-center">
                        <button
                          className="btn btn-danger d-inline-flex align-items-center gap-2"
                          style={{ borderRadius: "10px", fontSize: "0.84rem", fontWeight: "600", padding: "9px 18px" }}
                          onClick={() => setShowProfileModal(true)}
                        >
                          <FaBuilding style={{ fontSize: "14px" }} />
                          Company Profile
                        </button>
                      </div>

                      {/* Stats Cards */}
                      <div className="col-md-4">
                        <div className="d-flex align-items-center gap-2 dashmain_box">
                          <div className="icon_img"><File /></div>
                          <div className="d-flex flex-column gap-0">
                            <h4>Total Docs</h4>
                            <p>{istotalDocs}</p>
                          </div>
                        </div>
                      </div>

                      <div className="col-md-4">
                        <div className="d-flex align-items-center gap-2 dashmain_box">
                          <div className="icon_img"><FileText /></div>
                          <div className="d-flex flex-column gap-0">
                            <h4>Total Investor</h4>
                            <p>{InvestorDetail.length}</p>
                          </div>
                        </div>
                      </div>

                      <div className="col-md-4">
                        <div className="d-flex align-items-center gap-2 dashmain_box">
                          <div className="icon_img"><Share2 /></div>
                          <div className="d-flex flex-column gap-0">
                            <h4>Shared Reports</h4>
                            <p>{total_shared_reports}</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="col-12">
                    <div className="card p-3">
                      <h5 className="mb-3">Investors</h5>
                      <div className="d-flex flex-column justify-content-between align-items-start tb-box">
                        <style>{`.datatb-report { overflow: visible !important; }`}</style>
                        <DataTable
                          columns={columnsinvestor}
                          data={filteredInvestors}
                          pagination
                          highlightOnHover
                          striped
                          responsive
                          customStyles={customStyles}
                          className="custom-scrollbar custome-icon datatb-report"
                          noDataComponent={
                            <div className="text-center py-2"><span>No users found</span></div>
                          }
                        />
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        </div>
      </div>

      {/* ── Company Profile Modal ── */}
      <CompanyProfileModal
        show={showProfileModal}
        onHide={() => setShowProfileModal(false)}
        companyId={id}
      />

      {/* Signatory Role Modal */}
      <Modal
        title="Signatory Role"
        visible={isModalVisible}
        onOk={handleCloseModal}
        onCancel={handleCloseModal}
        okText="Close"
      >
        <p>{selectedRole || "No role assigned"}</p>
      </Modal>
    </>
  );
}

export default AdminUserAllDetails;